// components/stats-cards.tsx
import { prisma } from '@/lib/prisma';
import { Users, DollarSign, ShoppingCart, TrendingUp } from 'lucide-react';

async function getStats() {
  const [totalUsers, totalRevenue, totalOrders, growth] = await Promise.all([
    prisma.user.count(),
    prisma.order.aggregate({ _sum: { total: true } }),
    prisma.order.count(),
    prisma.order.aggregate({
      _avg: { total: true },
      where: { createdAt: { gte: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000) } },
    }),
  ]);

  return {
    totalUsers,
    totalRevenue: totalRevenue._sum.total || 0,
    totalOrders,
    avgOrder: growth._avg.total || 0,
  };
}

export async function StatsCards() {
  const stats = await getStats();

  const cards = [
    { label: 'Total Users', value: stats.totalUsers.toLocaleString(), icon: Users, change: '+12%', color: 'bg-blue-500' },
    { label: 'Revenue', value: `$${stats.totalRevenue.toLocaleString()}`, icon: DollarSign, change: '+8%', color: 'bg-green-500' },
    { label: 'Orders', value: stats.totalOrders.toLocaleString(), icon: ShoppingCart, change: '+23%', color: 'bg-purple-500' },
    { label: 'Avg Order', value: `$${stats.avgOrder.toFixed(2)}`, icon: TrendingUp, change: '+5%', color: 'bg-orange-500' },
  ];

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
      {cards.map((card) => (
        <div key={card.label} className="bg-white rounded-xl border p-6 shadow-sm">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-gray-500">{card.label}</p>
              <p className="text-2xl font-bold mt-1">{card.value}</p>
              <p className="text-xs text-green-600 mt-1">{card.change} from last month</p>
            </div>
            <div className={`p-3 rounded-lg ${card.color}`}>
              <card.icon className="w-6 h-6 text-white" />
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}
