# optimizer/profiler.py
"""Performance profiler for identifying bottlenecks."""

import time
import cProfile
import pstats
import io
import tracemalloc
from dataclasses import dataclass, field
from typing import Callable, Any
from functools import wraps
from collections import defaultdict


@dataclass
class ProfileResult:
    function_name: str
    total_time: float
    call_count: int
    avg_time: float
    memory_peak: int
    memory_delta: int
    suggestions: list[str] = field(default_factory=list)


class PerformanceProfiler:
    """Profile code and identify bottlenecks."""

    def __init__(self):
        self.results: list[ProfileResult] = []
        self.call_times: dict[str, list[float]] = defaultdict(list)
        self.memory_usage: dict[str, list[int]] = defaultdict(list)

    def profile_function(self, func: Callable) -> Callable:
        """Decorator to profile a function."""
        @wraps(func)
        def wrapper(*args, **kwargs):
            tracemalloc.start()
            start = time.perf_counter()
            result = func(*args, **kwargs)
            elapsed = time.perf_counter() - start
            current, peak = tracemalloc.get_traced_memory()
            tracemalloc.stop()

            self.call_times[func.__qualname__].append(elapsed)
            self.memory_usage[func.__qualname__].append(peak)

            return result
        return wrapper

    def profile_code(self, code_string: str, context: dict = None) -> ProfileResult:
        """Profile a code string."""
        profiler = cProfile.Profile()
        profiler.enable()

        if context:
            exec(code_string, context)
        else:
            exec(code_string)

        profiler.disable()

        stream = io.StringIO()
        stats = pstats.Stats(profiler, stream=stream)
        stats.sort_stats('cumulative')

        results = []
        for func, (cc, nc, tt, ct, callers) in stats.stats.items():
            results.append({
                'function': f"{func[0]}:{func[1]}({func[2]})",
                'total_time': tt,
                'call_count': nc,
                'avg_time': tt / max(nc, 1),
            })

        results.sort(key=lambda x: x['total_time'], reverse=True)
        return results[:10]  # Top 10 bottlenecks

    def get_optimization_suggestions(self) -> list[str]:
        """Generate optimization suggestions based on profiling data."""
        suggestions = []
        for name, times in self.call_times.items():
            if len(times) < 2:
                continue
            avg_time = sum(times) / len(times)
            if avg_time > 1.0:
                suggestions.append(f"{name}: Slow ({avg_time:.2f}s avg). Consider caching or optimization.")
            elif avg_time > 0.1:
                suggestions.append(f"{name}: Moderate ({avg_time:.3f}s avg). Consider profiling.")

        for name, memory in self.memory_usage.items():
            if memory and max(memory) > 100 * 1024 * 1024:  # > 100MB
                suggestions.append(f"{name}: High memory usage ({max(memory) / 1024 / 1024:.1f}MB). Consider streaming.")

        return suggestions

    def generate_report(self) -> str:
        """Generate a comprehensive profiling report."""
        report = ["=" * 60, "PERFORMANCE PROFILE REPORT", "=" * 60]
        report.append(f"\nFunctions profiled: {len(self.call_times)}")

        report.append("\n--- Top Slowest Functions ---")
        all_funcs = []
        for name, times in self.call_times.items():
            all_funcs.append({
                'name': name,
                'avg': sum(times) / len(times),
                'total': sum(times),
                'calls': len(times),
            })
        all_funcs.sort(key=lambda x: x['total'], reverse=True)

        for f in all_funcs[:20]:
            report.append(f"  {f['name']}: {f['avg']:.4f}s avg, {f['total']:.4f}s total, {f['calls']} calls")

        suggestions = self.get_optimization_suggestions()
        if suggestions:
            report.append("\n--- Optimization Suggestions ---")
            for s in suggestions:
                report.append(f"  - {s}")

        return "\n".join(report)
