# optimizer/cache.py
"""Intelligent caching system with TTL, LRU, and cache warming."""

import time
import hashlib
import json
import pickle
from collections import OrderedDict
from dataclasses import dataclass, field
from typing import Any, Optional, Callable
from functools import wraps
import threading


@dataclass
class CacheEntry:
    key: str
    value: Any
    created_at: float
    ttl: float
    access_count: int = 0
    last_accessed: float = 0

    @property
    def is_expired(self) -> bool:
        return time.time() - self.created_at > self.ttl

    @property
    def size_bytes(self) -> int:
        return len(pickle.dumps(self.value))


class LRUCache:
    """Thread-safe LRU cache with TTL support."""

    def __init__(self, max_size: int = 1000, default_ttl: float = 300):
        self.max_size = max_size
        self.default_ttl = default_ttl
        self.cache: OrderedDict[str, CacheEntry] = OrderedDict()
        self.lock = threading.RLock()
        self.hits = 0
        self.misses = 0

    def get(self, key: str) -> Optional[Any]:
        with self.lock:
            if key in self.cache:
                entry = self.cache[key]
                if entry.is_expired:
                    del self.cache[key]
                    self.misses += 1
                    return None
                entry.access_count += 1
                entry.last_accessed = time.time()
                self.cache.move_to_end(key)
                self.hits += 1
                return entry.value
            self.misses += 1
            return None

    def set(self, key: str, value: Any, ttl: float = None):
        with self.lock:
            if key in self.cache:
                del self.cache[key]
            elif len(self.cache) >= self.max_size:
                self.cache.popitem(last=False)
            self.cache[key] = CacheEntry(
                key=key,
                value=value,
                created_at=time.time(),
                ttl=ttl or self.default_ttl,
            )

    def invalidate(self, key: str) -> bool:
        with self.lock:
            if key in self.cache:
                del self.cache[key]
                return True
            return False

    def clear(self):
        with self.lock:
            self.cache.clear()

    @property
    def stats(self) -> dict:
        total = self.hits + self.misses
        return {
            'size': len(self.cache),
            'hits': self.hits,
            'misses': self.misses,
            'hit_rate': self.hits / max(total, 1),
            'memory_mb': sum(e.size_bytes for e in self.cache.values()) / 1024 / 1024,
        }


class CacheOptimizer:
    """Intelligent caching with automatic cache warming and invalidation."""

    def __init__(self, max_size: int = 1000):
        self.cache = LRUCache(max_size)
        self.warmup_functions: dict[str, Callable] = {}

    def cached(self, ttl: float = 300, key_prefix: str = ""):
        """Decorator for caching function results."""
        def decorator(func: Callable) -> Callable:
            @wraps(func)
            def wrapper(*args, **kwargs):
                cache_key = self._make_key(func, args, kwargs, key_prefix)
                result = self.cache.get(cache_key)
                if result is not None:
                    return result
                result = func(*args, **kwargs)
                self.cache.set(cache_key, result, ttl)
                return result
            return wrapper
        return decorator

    def warm_cache(self, key: str, fetcher: Callable, ttl: float = 300):
        """Pre-warm cache with data."""
        try:
            data = fetcher()
            self.cache.set(key, data, ttl)
        except Exception as e:
            print(f"Cache warmup failed for {key}: {e}")

    def invalidate_pattern(self, pattern: str):
        """Invalidate all keys matching a pattern."""
        keys_to_remove = [k for k in self.cache.cache.keys() if pattern in k]
        for key in keys_to_remove:
            self.cache.invalidate(key)

    def _make_key(self, func: Callable, args: tuple, kwargs: dict, prefix: str) -> str:
        key_parts = [prefix, func.__qualname__, str(args), str(sorted(kwargs.items()))]
        return hashlib.md5":".join(key_parts).encode()).hexdigest()

    def get_stats(self) -> dict:
        return self.cache.stats
