# optimizer/code_splitter.py
"""Automatic code splitting and lazy loading optimizer."""

import re
import ast
from pathlib import Path
from dataclasses import dataclass
from typing import Optional


@dataclass
class SplitPoint:
    file_path: str
    line_number: int
    reason: str
    chunk_name: str
    imports: list[str]
    exports: list[str]


class CodeSplitter:
    """Analyze and split code for optimal loading."""

    def __init__(self):
        self.split_points: list[SplitPoint] = []

    def analyze_file(self, file_path: str) -> list[SplitPoint]:
        """Analyze a file for code splitting opportunities."""
        path = Path(file_path)
        if not path.exists():
            return []

        content = path.read_text(encoding='utf-8')
        ext = path.suffix.lower()

        if ext in ['.tsx', '.jsx', '.ts', '.js']:
            return self._analyze_react(content, file_path)
        elif ext == '.py':
            return self._analyze_python(content, file_path)
        return []

    def _analyze_react(self, content: str, file_path: str) -> list[SplitPoint]:
        splits = []
        lines = content.split('\n')

        for i, line in enumerate(lines, 1):
            # Lazy import detection
            if 'React.lazy' in line or 'dynamic(' in line:
                splits.append(SplitPoint(
                    file_path=file_path, line_number=i,
                    reason="Already lazy loaded", chunk_name="dynamic",
                    imports=[], exports=[],
                ))

            # Large component detection
            if re.match(r'export\s+(default\s+)?function\s+(\w+)', line):
                func_name = re.search(r'function\s+(\w+)', line).group(1)
                # Check function size
                func_lines = 0
                for j in range(i, min(i + 200, len(lines))):
                    if lines[j].strip() and not lines[j].strip().startswith('//'):
                        func_lines += 1
                    if lines[j].strip() == '}' and func_lines > 50:
                        splits.append(SplitPoint(
                            file_path=file_path, line_number=i,
                            reason=f"Large component ({func_lines} lines)",
                            chunk_name=func_name.lower(),
                            imports=[], exports=[func_name],
                        ))
                        break

        return splits

    def _analyze_python(self, content: str, file_path: str) -> list[SplitPoint]:
        splits = []
        try:
            tree = ast.parse(content)
            for node in ast.walk(tree):
                if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    func_lines = node.end_lineno - node.lineno if hasattr(node, 'end_lineno') else 0
                    if func_lines > 50:
                        splits.append(SplitPoint(
                            file_path=file_path, line_number=node.lineno,
                            reason=f"Large function ({func_lines} lines)",
                            chunk_name=node.name,
                            imports=[], exports=[node.name],
                        ))
        except SyntaxError:
            pass
        return splits

    def generate_split_config(self, file_path: str) -> dict:
        """Generate Next.js dynamic import config."""
        splits = self.analyze_file(file_path)
        if not splits:
            return {}

        config = {
            'dynamicImports': [],
            'lazyComponents': [],
        }

        for split in splits:
            config['dynamicImports'].append({
                'component': split.chunk_name,
                'path': f"@/components/{split.chunk_name}",
                'chunkName': split.chunk_name,
            })

        return config
