# optimizer/auto_optimizer.py
"""Automatic optimization engine that applies improvements."""

import os
import json
import re
from pathlib import Path
from dataclasses import dataclass, field
from typing import Optional
from .profiler import PerformanceProfiler
from .cache import CacheOptimizer
from .code_splitter import CodeSplitter


@dataclass
class OptimizationReport:
    file_path: str
    original_size: int
    optimizations: list[dict] = field(default_factory=list)
    estimated_improvement: float = 0.0
    applied: bool = False


class AutoOptimizer:
    """Automatically analyze and optimize codebases."""

    def __init__(self, project_path: str):
        self.project_path = Path(project_path)
        self.profiler = PerformanceProfiler()
        self.cache = CacheOptimizer()
        self.splitter = CodeSplitter()
        self.reports: list[OptimizationReport] = []

    def analyze_project(self) -> dict:
        """Analyze entire project for optimization opportunities."""
        analysis = {
            'files_analyzed': 0,
            'total_size': 0,
            'optimizations_found': 0,
            'categories': {},
        }

        for file_path in self.project_path.rglob('*'):
            if file_path.is_file() and file_path.suffix in ['.py', '.js', '.ts', '.tsx', '.jsx']:
                report = self._analyze_file(file_path)
                if report:
                    self.reports.append(report)
                    analysis['files_analyzed'] += 1
                    analysis['total_size'] += report.original_size
                    analysis['optimizations_found'] += len(report.optimizations)
                    for opt in report.optimizations:
                        cat = opt.get('category', 'other')
                        analysis['categories'][cat] = analysis['categories'].get(cat, 0) + 1

        return analysis

    def _analyze_file(self, file_path: Path) -> Optional[OptimizationReport]:
        try:
            content = file_path.read_text(encoding='utf-8')
            report = OptimizationReport(
                file_path=str(file_path),
                original_size=len(content.encode()),
            )

            # Check for common inefficiencies
            optimizations = []

            # 1. Unused imports
            if file_path.suffix == '.py':
                unused = self._find_unused_imports(content)
                if unused:
                    optimizations.append({
                        'type': 'remove_unused_imports',
                        'category': 'code_quality',
                        'details': unused,
                        'impact': 'low',
                    })

            # 2. Missing caching
            if 'def ' in content and '@cached' not in content and 'cache' not in content.lower():
                optimizations.append({
                    'type': 'add_caching',
                    'category': 'performance',
                    'details': 'Function could benefit from caching',
                    'impact': 'medium',
                })

            # 3. Large bundles (React)
            if any(ext in file_path.suffix for ext in ['.tsx', '.jsx']):
                if len(content) > 10000:
                    optimizations.append({
                        'type': 'code_splitting',
                        'category': 'bundle_size',
                        'details': f'File is {len(content)} bytes, consider splitting',
                        'impact': 'high',
                    })

            # 4. Database queries without indexes
            if 'findMany' in content or 'SELECT' in content.upper():
                if 'index' not in content.lower():
                    optimizations.append({
                        'type': 'add_database_index',
                        'category': 'database',
                        'details': 'Query may need database index',
                        'impact': 'high',
                    })

            # 5. Missing error handling
            if 'async' in content and 'try' not in content:
                optimizations.append({
                    'type': 'add_error_handling',
                    'category': 'reliability',
                    'details': 'Async code without error handling',
                    'impact': 'medium',
                })

            report.optimizations = optimizations
            return report if optimizations else None

        except Exception:
            return None

    def _find_unused_imports(self, content: str) -> list[str]:
        """Find unused imports in Python code."""
        lines = content.split('\n')
        imports = []
        for i, line in enumerate(lines):
            if line.strip().startswith('import ') or line.strip().startswith('from '):
                match = re.search(r'import\s+(\w+)', line)
                if match:
                    imports.append((i + 1, match.group(1)))

        unused = []
        for line_num, imp in imports:
            # Check if import is used (simple check)
            count = content.count(imp)
            if count <= 1:  # Only the import itself
                unused.append(f"Line {line_num}: {imp}")

        return unused

    def apply_optimizations(self, dry_run: bool = True) -> list[dict]:
        """Apply optimizations to the codebase."""
        results = []
        for report in self.reports:
            for opt in report.optimizations:
                result = {
                    'file': report.file_path,
                    'optimization': opt['type'],
                    'status': 'would_apply' if dry_run else 'applied',
                }
                if not dry_run:
                    self._apply_single_optimization(report.file_path, opt)
                results.append(result)
        return results

    def _apply_single_optimization(self, file_path: str, optimization: dict):
        """Apply a single optimization."""
        if optimization['type'] == 'remove_unused_imports':
            path = Path(file_path)
            content = path.read_text(encoding='utf-8')
            for detail in optimization['details']:
                line_num = int(detail.split(':')[0].replace('Line ', ''))
                lines = content.split('\n')
                if line_num <= len(lines):
                    lines[line_num - 1] = ''  # Remove the line
            content = '\n'.join(line for line in lines if line)
            path.write_text(content, encoding='utf-8')

    def generate_report(self) -> str:
        """Generate a comprehensive optimization report."""
        report = ["=" * 60, "OPTIMIZATION REPORT", "=" * 60]
        report.append(f"\nFiles analyzed: {len(self.reports)}")
        total_opts = sum(len(r.optimizations) for r in self.reports)
        report.append(f"Optimizations found: {total_opts}")

        # Group by category
        categories = {}
        for r in self.reports:
            for opt in r.optimizations:
                cat = opt.get('category', 'other')
                categories.setdefault(cat, []).append(opt)

        for cat, opts in sorted(categories.items()):
            report.append(f"\n--- {cat.replace('_', ' ').title()} ({len(opts)}) ---")
            for opt in opts[:5]:
                report.append(f"  [{opt['impact'].upper()}] {opt['type']}: {opt.get('details', '')}")

        return "\n".join(report)
