# tool_system/registry.py
"""Tool registration and management."""

import inspect
from dataclasses import dataclass, field
from typing import Any, Callable, Optional


@dataclass
class ToolParameter:
    name: str
    type: str
    description: str = ""
    required: bool = True
    enum: list[str] = field(default_factory=list)
    default: Any = None

    def to_schema(self) -> dict:
        schema = {"type": self.type}
        if self.description: schema["description"] = self.description
        if self.enum: schema["enum"] = self.enum
        if self.default is not None: schema["default"] = self.default
        return schema


@dataclass
class Tool:
    name: str
    description: str
    parameters: list[ToolParameter]
    handler: Callable
    category: str = "general"
    tags: list[str] = field(default_factory=list)

    def to_schema(self) -> dict:
        properties = {}
        required = []
        for param in self.parameters:
            properties[param.name] = param.to_schema()
            if param.required: required.append(param.name)
        return {
            "name": self.name,
            "description": self.description,
            "input_schema": {
                "type": "object",
                "properties": properties,
                "required": required,
            },
        }

    def validate_input(self, data: dict) -> tuple[bool, str]:
        for param in self.parameters:
            if param.required and param.name not in data:
                return False, f"Missing: {param.name}"
            if param.name in data and param.enum and data[param.name] not in param.enum:
                return False, f"Invalid value for {param.name}: must be one of {param.enum}"
        return True, ""


class ToolRegistry:
    """Registry for managing tools."""

    def __init__(self):
        self._tools: dict[str, Tool] = {}

    def register(self, name: str, description: str, parameters: list[ToolParameter],
                 handler: Callable, category: str = "general", tags: list[str] = None) -> Tool:
        tool = Tool(name=name, description=description, parameters=parameters,
                    handler=handler, category=category, tags=tags or [])
        self._tools[name] = tool
        return tool

    def register_function(self, func: Callable, name: str = None, description: str = None) -> Tool:
        tool_name = name or func.__name__
        tool_desc = description or func.__doc__ or f"Execute {tool_name}"
        sig = inspect.signature(func)
        parameters = []
        for pname, param in sig.parameters.items():
            if pname == "self": continue
            ptype = "string"
            if param.annotation == int: ptype = "integer"
            elif param.annotation == float: ptype = "number"
            elif param.annotation == bool: ptype = "boolean"
            parameters.append(ToolParameter(name=pname, type=ptype, required=param.default == inspect.Parameter.empty))
        return self.register(tool_name, tool_desc, parameters, func)

    def get(self, name: str) -> Optional[Tool]: return self._tools.get(name)
    def has(self, name: str) -> bool: return name in self._tools
    def list_tools(self) -> list[Tool]: return list(self._tools.values())
    def get_schemas(self) -> list[dict]: return [t.to_schema() for t in self._tools.values()]

    def validate_input(self, tool_name: str, data: dict) -> tuple[bool, str]:
        tool = self._tools.get(tool_name)
        if not tool: return False, f"Unknown tool: {tool_name}"
        return tool.validate_input(data)
