"""Parse tool calls from model output."""

import json
import re
from dataclasses import dataclass
from typing import Optional


@dataclass
class ParsedToolCall:
    id: str
    name: str
    input: dict
    raw_text: str = ""
    confidence: float = 1.0


class ToolParser:
    """Parse tool calls from model output in multiple formats."""

    def __init__(self, registry=None):
        self._registry = registry
        self._counter = 0

    def _gen_id(self) -> str:
        self._counter += 1
        return f"toolu_{self._counter:06d}"

    def parse(self, text: str) -> list[ParsedToolCall]:
        calls = []
        calls.extend(self._parse_json_blocks(text))
        if not calls: calls.extend(self._parse_function_calls(text))
        if not calls: calls.extend(self._parse_xml_tools(text))
        return calls

    def _parse_json_blocks(self, text: str) -> list[ParsedToolCall]:
        calls = []
        for pattern in [r'\{[^{}]*"tool"[^{}]*\}', r'\{[^{}]*"name"[^{}]*\}']:
            for match in re.finditer(pattern, text, re.DOTALL):
                try:
                    block = json.loads(match.group())
                    name = block.get('tool') or block.get('name')
                    if name:
                        params = block.get('parameters') or block.get('input') or {}
                        calls.append(ParsedToolCall(id=self._gen_id(), name=name, input=params, raw_text=match.group()))
                except json.JSONDecodeError: continue
        return calls

    def _parse_function_calls(self, text: str) -> list[ParsedToolCall]:
        calls = []
        for match in re.finditer(r'(\w+)\(([^)]*)\)', text):
            func_name = match.group(1)
            if self._registry and not self._registry.has(func_name): continue
            params = {}
            for arg in match.group(2).split(','):
                arg = arg.strip()
                if '=' in arg:
                    k, v = arg.split('=', 1)
                    params[k.strip()] = v.strip().strip('"').strip("'")
            calls.append(ParsedToolCall(id=self._gen_id(), name=func_name, input=params, raw_text=match.group(), confidence=0.7))
        return calls

    def _parse_xml_tools(self, text: str) -> list[ParsedToolCall]:
        calls = []
        for match in re.finditer(r'<tool_call\s+name="([^"]+)">(.*?)</tool_call>', text, re.DOTALL):
            try: params = json.loads(match.group(2))
            except: params = {"text": match.group(2)}
            calls.append(ParsedToolCall(id=self._gen_id(), name=match.group(1), input=params, raw_text=match.group()))
        return calls
