# tool_system/executor.py
"""Sandboxed tool execution with retry logic."""

import time
import traceback
from dataclasses import dataclass
from typing import Any, Callable, Optional


@dataclass
class ExecutionResult:
    tool_use_id: str
    tool_name: str
    success: bool
    output: Any = None
    error: str = ""
    duration_ms: float = 0
    is_error: bool = False

    def to_tool_result(self) -> dict:
        content = self.output if self.success else f"Error: {self.error}"
        if not isinstance(content, str): content = str(content)
        return {"type": "tool_result", "tool_use_id": self.tool_use_id, "content": content, "is_error": self.is_error}


class ToolExecutor:
    """Execute tools with safety controls."""

    def __init__(self, registry=None, timeout: float = 30, max_retries: int = 2):
        self._registry = registry
        self._timeout = timeout
        self._max_retries = max_retries
        self._history: list[ExecutionResult] = []

    def execute(self, tool_name: str, tool_input: dict, tool_use_id: str = None) -> ExecutionResult:
        if tool_use_id is None: tool_use_id = f"toolu_{int(time.time() * 1000)}"

        if self._registry and not self._registry.has(tool_name):
            return ExecutionResult(tool_use_id=tool_use_id, tool_name=tool_name, success=False, error=f"Unknown tool: {tool_name}", is_error=True)

        valid, msg = self._registry.validate_input(tool_name, tool_input) if self._registry else (True, "")
        if not valid:
            return ExecutionResult(tool_use_id=tool_use_id, tool_name=tool_name, success=False, error=f"Invalid input: {msg}", is_error=True)

        handler = self._registry.get(tool_name).handler if self._registry else None
        last_error = None

        for attempt in range(self._max_retries + 1):
            start = time.time()
            try:
                output = handler(**tool_input)
                result = ExecutionResult(tool_use_id=tool_use_id, tool_name=tool_name, success=True, output=output, duration_ms=(time.time() - start) * 1000)
                self._history.append(result)
                return result
            except Exception as e:
                last_error = f"{type(e).__name__}: {e}"
                if attempt < self._max_retries: time.sleep(0.1 * (attempt + 1))

        result = ExecutionResult(tool_use_id=tool_use_id, tool_name=tool_name, success=False, error=last_error, is_error=True)
        self._history.append(result)
        return result

    def execute_batch(self, tool_calls: list[dict]) -> list[ExecutionResult]:
        return [self.execute(tc.get('name', ''), tc.get('input', {}), tc.get('id')) for tc in tool_calls]

    def get_stats(self) -> dict:
        total = len(self._history)
        success = sum(1 for r in self._history if r.success)
        return {"total": total, "success": success, "failed": total - success, "success_rate": success / max(total, 1)}
