"""Claude-compatible API format for tool use."""

import json
import time
from dataclasses import dataclass, field
from typing import Optional


@dataclass
class ClaudeToolUse:
    id: str
    name: str
    input: dict
    def to_dict(self): return {"type": "tool_use", "id": self.id, "name": self.name, "input": self.input}


@dataclass
class ClaudeToolResult:
    tool_use_id: str
    content: str
    is_error: bool = False
    def to_dict(self):
        d = {"type": "tool_result", "tool_use_id": self.tool_use_id, "content": self.content}
        if self.is_error: d["is_error"] = True
        return d


@dataclass
class ClaudeToolChoice:
    type: str  # auto, any, tool, none
    name: Optional[str] = None
    def to_dict(self):
        d = {"type": self.type}
        if self.name: d["name"] = self.name
        return d
    @classmethod
    def auto(cls): return cls(type="auto")
    @classmethod
    def any(cls): return cls(type="any")
    @classmethod
    def tool(cls, name): return cls(type="tool", name=name)
    @classmethod
    def none(cls): return cls(type="none")


def format_tools_for_api(tools: list[dict]) -> list[dict]:
    return [{"name": t.get("name"), "description": t.get("description"), "input_schema": t.get("input_schema", {"type": "object", "properties": {}})} for t in tools]


def create_tool_use_message(tool_calls: list[dict]) -> dict:
    content = [{"type": "tool_use", "id": tc.get("id", f"toolu_{int(time.time()*1000)}"), "name": tc.get("name"), "input": tc.get("input", {})} for tc in tool_calls]
    return {"role": "assistant", "content": content}


def create_tool_result_message(results: list[dict]) -> dict:
    content = []
    for r in results:
        block = {"type": "tool_result", "tool_use_id": r.get("tool_use_id"), "content": r.get("content", "")}
        if r.get("is_error"): block["is_error"] = True
        content.append(block)
    return {"role": "user", "content": content}


def build_conversation(messages: list[dict], tool_results: list[dict]) -> list[dict]:
    conversation = list(messages)
    conversation.append(create_tool_result_message(tool_results))
    return conversation


def extract_text(response: dict) -> str:
    content = response.get("content", [])
    if isinstance(content, str): return content
    return "\n".join(b.get("text", "") for b in content if isinstance(b, dict) and b.get("type") == "text")


def extract_tool_calls(response: dict) -> list[ClaudeToolUse]:
    calls = []
    for b in response.get("content", []):
        if isinstance(b, dict) and b.get("type") == "tool_use":
            calls.append(ClaudeToolUse(id=b["id"], name=b["name"], input=b["input"]))
    return calls
